import PropTypes from 'prop-types'
// @mui
import { styled } from '@mui/material/styles'
import { ListItemButton, Popover, Typography } from '@mui/material'
import { useRef, useState } from 'react'

import { useNavigate, useParams } from 'react-router'

import MailIcon from 'src/assets/IconSet/Email'
import ShareIcon from 'src/assets/IconSet/Share'
import QrIcon from 'src/assets/IconSet/Qrcode'
import EditIcon from 'src/assets/IconSet/edit'
import UnarchiveIcon from 'src/assets/IconSet/CheckDoc'
import CopyLinkIcon from 'src/assets/IconSet/CopyLink'
import { updateFeedback } from 'src/redux/actions/feedback'
import { useDispatch } from 'react-redux'
export default function ProgramOverviewPopover(props) {
    const dispatch = useDispatch()

    const [openedPopover, setOpenedPopover] = useState(false)
    const navigate = useNavigate()

    const { id } = useParams()
    const popoverAnchor = useRef(null)
const copyProfile = (e) => {
    e.stopPropagation()
    setOpenedPopover(false)
    navigator.clipboard.writeText(
        window.location.origin+`/public/instructor-profile/${props.profile._id}`
    )
  
    dispatch(updateFeedback({ snackbar: true, message: 'Copied' }))
    }

    const shareWorkout = (e) => {
        e.stopPropagation()
        if (navigator.share) {
            navigator
                .share({
                    title: `Circled Fitness Instructor :${props.profile.name}`,
                    url: `/public/instructor-profile/${props.profile._id}`,
                })
                .then(() => {})
        }
    }
    return (
        <div>
            {' '}
            <span ref={popoverAnchor} onClick={() => setOpenedPopover(true)}>
                {props.children}
            </span>
            <Popover
                id="mouse-click-popover"
                open={openedPopover}
                onClose={() => setOpenedPopover(false)}
                anchorReference="anchorEl"
                anchorEl={popoverAnchor.current}
                PaperProps={{
                    sx: {
                        width: 175,
                        borderRadius: 0.8,
                        py: 1.5,
                        borderRadius: 2,
                        boxShadow: (theme) => theme.customShadows.z20,
                        border: (theme) =>
                            `solid 1px ${theme.palette.grey[500_12]}`,
                    },
                }}
                anchorOrigin={{
                    vertical: 'bottom',
                    horizontal: 'right',
                }}
                transformOrigin={{
                    vertical: 'top',
                    horizontal: 'right',
                }}
            >
                <ListItemButton
                    onClick={copyProfile}
                    sx={{ py: 1.5 }}
                >
                    <CopyLinkIcon />
                    &nbsp;&nbsp;&nbsp;
                    <Typography>Copy link</Typography>
                </ListItemButton>
                <ListItemButton
                    sx={{ py: 1.5 }}
                    onClick={
                        (e) => {
                            shareWorkout(e)
                            // props.shareWorkout()
                            setOpenedPopover(false)
                        }
                        // setSelected(item);
                    }
                >
                    <ShareIcon />
                    &nbsp;&nbsp;&nbsp;
                    <Typography>Share</Typography>
                </ListItemButton>
            </Popover>
        </div>
    )
}
